import pytest
import uuid

def test_limit_at_exact_regulatory_cap_is_accepted(
    auth_client,
    account_id,
    regulatory_cap,
):
    idempotency_key = str(uuid.uuid4())
    payload = {"channel": "online", "daily_limit": regulatory_cap}
    headers = {"Idempotency-Key": idempotency_key}

    resp = auth_client.post(
        f"/accounts/{account_id}/limits",
        json=payload,
        headers=headers,
    )

    assert resp.status_code == 202, (
        f"Expected 202 at cap boundary, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert body["status"] == "pending"
